import * as React from 'react'
import { Input } from '@/components/ui/input'
import type { BaseFormFieldProps } from '@/registry/lib/base-form-props'

export interface FormBytesArrayProps extends Omit<BaseFormFieldProps, 'value' | 'onChange'> {
  /** 当前值 */
  value?: string
  /** 值变化回调 */
  onChange?: (value: string) => void
  /** 占位文本 */
  placeholder?: string
  /** 是否禁用 */
  disabled?: boolean
}

const FormBytesArray: React.FC<FormBytesArrayProps> = (props) => {
  const { value, onChange, placeholder, disabled } = props

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(e.target.value)
  }

  return (
    <Input
      value={value || ''}
      onChange={handleChange}
      placeholder={placeholder || '请输入内容'}
      disabled={disabled}
    />
  )
}

export { FormBytesArray }

import type { Ref } from 'react'

/** 所有通过 FormField 使用的组件共享的 props */
export interface BaseFormFieldProps {
  /** 当前值（react-hook-form） */
  value?: any
  /** 值变更回调（react-hook-form） */
  onChange?: (value: any) => void
  /** 失焦回调（react-hook-form） */
  onBlur?: () => void
  /** 字段名（react-hook-form） */
  name?: string
  /** ref（react-hook-form） */
  ref?: Ref<any>
  /** 字段 ID（FormField 生成） */
  id?: string
  /** 表单 schema */
  schema?: Record<string, any>
  /** 表单记录数据 */
  record?: any
}

/** 选项类型 */
export interface FormOption {
  value: string | number
  label?: string
  disabled?: boolean
}
